console.log(`Inserting ${scholarships.length} scholarships…`);

// Insert in batches of 25 to stay within Supabase request limits
const BATCH = 25;
let inserted = 0;
let errors = 0;

for (let i = 0; i < scholarships.length; i += BATCH) {
  const batch = scholarships.slice(i, i + BATCH);
  const res = await fetch(`${SUPABASE_URL}/rest/v1/scholarships`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "apikey": SUPABASE_KEY,
      "Authorization": `Bearer ${SUPABASE_KEY}`,
      "Prefer": "return=minimal",
    },
    body: JSON.stringify(batch),
  });

  if (res.ok) {
    inserted += batch.length;
    console.log(`  ✓ Batch ${Math.floor(i / BATCH) + 1}: inserted ${batch.length} (total ${inserted})`);
  } else {
    const body = await res.json().catch(() => ({}));
    console.error(`  ✗ Batch ${Math.floor(i / BATCH) + 1} failed (${res.status}):`, JSON.stringify(body).slice(0, 200));
    errors++;
  }
}

console.log(`\nDone — ${inserted} inserted, ${errors} batch errors.`);
